solution.code:
use std::fmt::Display;

struct Stack<T> {
    data: Vec<T>,
}

impl<T: Display> Stack<T> {
    pub fn new() -> Self {
        Stack { data: Vec::new() }
    }

    pub fn push(&mut self, item: T) {
        self.data.push(item);
    }

    pub fn pop(&mut self) -> Option<T> {
        self.data.pop()
    }

    pub fn peek(&self) -> Option<&T> {
        self.data.last()
    }

    pub fn print_all(&self) {
        for item in &self.data {
            println!("{}", item);
        }
    }
}
